class Solution:
    def surfaceArea(self, grid):
        n = len(grid)
        total = 0
        for i in range(n):
            for j in range(n):
                v = grid[i][j]
                if v > 0:
                    total += 4 * v + 2
                for di, dj in ((1, 0), (0, 1)):
                    ni, nj = i + di, j + dj
                    if ni < n and nj < n:
                        total -= 2 * min(v, grid[ni][nj])
        return total

