var surfaceArea = function(grid) {
    const n = grid.length;
    let area = 0;
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < n; j++) {
            const v = grid[i][j];
            if (v) area += 2 + 4 * v;
            if (i) area -= 2 * Math.min(v, grid[i - 1][j]);
            if (j) area -= 2 * Math.min(v, grid[i][j - 1]);
        }
    }
    return area;
};
